const trigger = $('SE Empty Guard').first().json;
const deal = $('Fetch Deal Details').first().json;
const se = $('Resolve SE Name').first().json;
const ae = $input.first().json;

const seName = `${se.firstName} ${se.lastName}`.trim();
const aeName = `${ae.firstName} ${ae.lastName}`.trim();
const seHubSpotId = String(deal.properties.solutions_engineer);

const SE_MAP = {
  '1891381453': { linearId: '127d293c-86a5-439d-be0e-31e59022e840', name: 'Harry Day' },
  '29995860':   { linearId: '633f0c0d-c45d-4fa1-b75d-0cced134efe3', name: 'Anastasia Screve' },
  '32163999':   { linearId: '1f66b0f0-3476-43dc-8c99-1899dcf4f79a', name: 'Stephanie Adriaens' }
};

const match = SE_MAP[seHubSpotId];
const linearUserId = match ? match.linearId : null;

if (!match) {
  console.log('WARNING: No Linear user mapping for SE ' + seName + ' (HubSpot ID: ' + seHubSpotId + ')');
}

const amount = Number(deal.properties.amount || 0);
const potentialAmount = Number(deal.properties.potential_amount || 0);
const formatCurrency = (v) => v >= 1000 ? '€' + (v / 1000).toFixed(0) + 'K' : '€' + v;
const formatFull = (v) => '€' + v.toLocaleString('en-IE', { minimumFractionDigits: 0, maximumFractionDigits: 0 });

const closedate = deal.properties.closedate
  ? new Date(deal.properties.closedate).toLocaleDateString('en-IE', { day: 'numeric', month: 'short', year: 'numeric' })
  : 'Not set';

const dealStage = deal.properties.dealstage || 'Unknown';

return [{
  json: {
    dealId: deal.id,
    dealName: deal.properties.dealname,
    dealStage: dealStage,
    amount: amount,
    amountAbbr: formatCurrency(amount),
    amountFormatted: formatFull(amount),
    potentialAmount: potentialAmount,
    potentialFormatted: formatFull(potentialAmount),
    closeDate: closedate,
    seName: seName,
    seHubSpotId: seHubSpotId,
    linearUserId: linearUserId,
    aeName: aeName,
    portalId: '142047914',
    objectId: trigger.objectId
  }
}];

const prev = $('Map SE → Linear User').first().json;

const title = prev.dealName + ' (' + prev.amountAbbr + ') — SE support';

const description = '**Deal**: ' + prev.dealName + '\n' +
  '**Stage**: ' + prev.dealStage + '\n' +
  '**Amount**: ' + prev.amountFormatted + '\n' +
  '**Potential**: ' + prev.potentialFormatted + '\n' +
  '**Close Date**: ' + prev.closeDate + '\n' +
  '**AE Owner**: ' + prev.aeName + '\n\n' +
  '🔗 [View in HubSpot](https://app.hubspot.com/contacts/' + prev.portalId + '/deal/' + prev.dealId + ')\n\n' +
  '---\n' +
  '*hs-deal-id:' + prev.dealId + '*';

return [{
  json: {
    title: title,
    description: description,
    linearUserId: prev.linearUserId,
    dealId: prev.dealId,
    portalId: prev.portalId
  }
}];
